    {
      "path": "materials.spreader_material.conductivity",
      "action": "set",
      "old": 453.6,
      "new": 500.0,
      "reason": "Increase spreader conductivity to the maximum allowed bound (500.0) to maximize lateral heat spreading and reduce the chip hot spot temperature. This step ratio (~1.1x) is within the permitted [0.5x, 2.0x] range."
    }
  ],
  "expected_effects": [
    "Reduced thermal resistance in the spreader layer",
    "Lower peak temperature in the chip component",
    "Improved feasibility regarding the chip_max_temperature constraint"
  ],
